class Solution {
public:
    bool containsNearbyDuplicate(vector<int>& nums, int k) {
        unordered_map<int,int> last;
        for (int i = 0; i < (int)nums.size(); i++) {
            if (last.count(nums[i]) && i - last[nums[i]] <= k) return true;
            last[nums[i]] = i;
        }
        return false;
    }
};

