bool containsNearbyDuplicate(int* nums, int n, int k) {
    /* value -> last index; linear scan with small open hash or sort pairs */
    for (int i = 0; i < n; i++)
        for (int j = i + 1; j <= i + k && j < n; j++)
            if (nums[i] == nums[j]) return true;
    return false;
}
